        }
        td {
          padding: 15px;
          padding-left: 25px;
        }
        td:nth-child(1) {
          width: 620px;
          text-align: left;
        }
      }
      & > tr:nth-child(17) {
        & > td:nth-child(2) {
          // text-align: left;
        }
      }
    }
    position: relative;
    &::after {
      content: '';
      position: absolute;
      width: 100%;
      border-bottom: 1px dashed;
      bottom: -20px;
      left: 0;
    }
  }
}

